package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetIgnoreEmptyLines_DefaultTrue() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertTrue(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_ExcelFalse() {
        CSVFormat format = CSVFormat.EXCEL;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_WithIgnoreEmptyLinesTrue() {
        CSVFormat base = CSVFormat.DEFAULT.withIgnoreEmptyLines(false);
        CSVFormat format = base.withIgnoreEmptyLines(true);
        assertTrue(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_WithIgnoreEmptyLinesFalse() {
        CSVFormat base = CSVFormat.DEFAULT.withIgnoreEmptyLines(true);
        CSVFormat format = base.withIgnoreEmptyLines(false);
        assertFalse(format.getIgnoreEmptyLines());
    }
}
